parameters.jsCode:
const query = $json.query || {};

const mode = query["hub.mode"];
const token = query["hub.verify_token"];
const challenge = query["hub.challenge"];

// USE AQUI O MESMO TOKEN QUE VAI DIGITAR NA META
const VERIFY_TOKEN = "KHA-TOKEN-040251";

if (mode === "subscribe" && token === VERIFY_TOKEN && challenge) {
  return [{ json: { response: challenge } }];
}

return [{ json: { response: "TOKEN_INVALIDO" } }];

// Aqui você já recebe o corpo do POST da Meta
const body = $json.body || $json;

// Só para debug: deixa o payload inteiro no item
return [{
  json: {
    response: "OK",
    incoming: body
  }
}];

const incoming = $json.body || $json;

const entry = incoming.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value || {};
const msg = value.messages?.[0] || {};
const contact = value.contacts?.[0] || {};

const from = msg.from;
const name = contact.profile?.name || '';

let text = '';
let contentType = msg.type || 'text';

// Caso 1: texto normal
if (msg.type === 'text') {
  text = msg.text?.body || '';
}

// Caso 2: mensagem interativa (botão ou lista)
else if (msg.type === 'interactive') {
  const interactive = msg.interactive || {};

  if (interactive.type === 'button_reply' && interactive.button_reply) {
    const id = interactive.button_reply.id;      // ex.: "menu_cardapio"
    text = id;
  }

  if (interactive.type === 'list_reply' && interactive.list_reply) {
    const id = interactive.list_reply.id;        // ex.: "menu_reserva"
    text = id;
  }

  // Tratar cliques de menu como TEXTO para o resto do fluxo
  contentType = 'text';
}

// Fallback: se ainda não tiver texto, garante string vazia
text = text || '';

const redisMessageId = `wa:${from}`;
const redisAttendentTimeOut = `wa_timeout:${from}`;

return [{
  json: {
    phone: from,
    name,
    menssage: text,              // mantém compatibilidade com o fluxo antigo
    message: text,               // opcional, nome “certo” se quiser usar depois
    content_type: contentType,   // "text" tanto para texto quanto para menu
    redisMessageId,
    redisAttendentTimeOut
  }
}];

